initial_model.plantuml:
@startuml
class Student {
    - studentCode : String
}
class Course {
    - courseName : String
}
class Enrollment {
    - enrollmentDate : Date
}
class TeachingAssistant {
    - firstName : String
    - lastName : String
}
class Assignment {
    - details : String
    - responsibilities : String
}
class LabSection {
    - location : String
    - startTime : Time
    - endTime : Time
}
Student "1" -- "0..*"  Enrollment : EnrollsIn
Course "1" -- "0..*"  Enrollment : HasEnrollment
LabSection "0..*" -- "0..*"  TeachingAssistant : SupportedBy
Course "1" *-- "1..*"  LabSection
(Student, Course) .. Enrollment
(TeachingAssistant, LabSection) .. LabSectionSupport
(Course, TeachingAssistant) .. Assignment
@enduml

